breach_action.script:
// On breach: Notify HR of overdue approval
var approval = current;
var empId = approval.document_id.getRefRecord().employee_id;
gs.eventQueue('x_empl_lifecycle.approval_escalated', approval, empId, approval.approver);
gs.log('APPROVAL SLA BREACHED: Manager approval overdue for Employee: ' + empId, 'LifecycleSLA');

var lifecycle = current;
var empId = lifecycle.employee_id.toString();
var reqType = lifecycle.request_type.toString();
gs.log('LIFECYCLE SLA BREACHED: Process overdue for Employee: ' + empId + ' (' + reqType + ')', 'LifecycleSLA');
gs.eventQueue('x_empl_lifecycle.sla_breached', lifecycle, empId, reqType);
